export default {
  props: {
    bot: Object,
    canRemove: Boolean
  },
  data() {
    return {
      iconError: false
    };
  },
  computed: {
    difficultyClass() {
      switch (this.bot.difficulty) {
        case "EASY":
          return "easy";
        case "NORMAL":
          return "normal";
        case "HARD":
          return "hard";
        default:
          return "normal";
      }
    },
    difficultyLabel() {
      switch (this.bot.difficulty) {
        case "EASY":
          return this.$translate.text("BOT_DIFFICULTY_EASY");
        case "NORMAL":
          return this.$translate.text("BOT_DIFFICULTY_NORMAL");
        case "HARD":
          return this.$translate.text("BOT_DIFFICULTY_HARD");
        default:
          return this.bot.difficulty;
      }
    }
  },
  methods: {
    getChampionImageUrl() {
      if (this.iconError) {
        return "";
      }
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `${host}:${port}/champions/${this.bot.championId}.jpg`;
    },
    onIconError() {
      this.iconError = true;
    }
  }
};
